<span class="line"><span style="color:#CDD6F4;">        score </span><span style="color:#94E2D5;">+=</span><span style="color:#CDD6F4;"> recency </span><span style="color:#94E2D5;">*</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">.</span><span style="color:#FAB387;">0</span><span style="color:#9399B2;">;</span></span>
